 * ================================================= */
void example_epoll_two_pipes(void) {
    int p1[2], p2[2];
    pipe(p1); pipe(p2);
    int epfd = epoll_create1(0);
    struct epoll_event ev;
    ev.events = EPOLLIN; ev.data.fd = p1[0];
    epoll_ctl(epfd, EPOLL_CTL_ADD, p1[0], &ev);
    ev.data.fd = p2[0];
    epoll_ctl(epfd, EPOLL_CTL_ADD, p2[0], &ev);
    write(p1[1], "A", 1); write(p2[1], "B", 1);
    struct epoll_event events[4];
    int n = epoll_wait(epfd, events, 4, 100);
    for (int i = 0; i < n; i++) {
        char c; read(events[i].data.fd, &c, 1);
        printf("Got: %c from fd %d\n", c, events[i].data.fd);
    }
    close(p1[0]); close(p1[1]); close(p2[0]); close(p2[1]); close(epfd);
}
